SELECT * FROM chat_messages_partitioned 
WHERE session_id = #{sessionId} AND target_agent = #{targetAgent}
ORDER BY created_at DESC

SELECT * FROM chat_messages_partitioned 
WHERE session_id = #{sessionId} AND created_at BETWEEN #{startTime} AND #{endTime}
ORDER BY created_at ASC

SELECT * FROM chat_messages_partitioned 
WHERE session_id = #{sessionId} AND id > #{lastId}
ORDER BY created_at ASC
